INSERT INTO shop_product (
    sku, title, vendor, plan_name, description, price, available_stock, sold_count, status, sort_order
) VALUES (
    #{sku}, #{title}, #{vendor}, #{planName}, #{description}, #{price}, #{availableStock}, #{soldCount}, #{status}, #{sortOrder}
)

mapper.update:
UPDATE shop_product
SET status = #{status}
WHERE id = #{id}

UPDATE shop_product
SET available_stock = available_stock + #{stockDelta},
    sold_count = sold_count + #{soldDelta}
WHERE id = #{id}
